1	const PROCESSING_FEE = 5;
2	const BLOCK_SIZE = 3;
3	const BLOCK_PREMIUM = 60;
4	
5	const BASE_PREMIUMS: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	export function claimOffice(request: any): any {
17	  const items = request.steps[0].items;
18	
19	  const componentCounts: Record<string, number> = {};
20	  for (const item of items) {
21	    if (COMPONENT_TYPES.has(item.type)) {
22	      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
23	    }
24	  }
25	
26	  let basePremium = 0;
27	  const blocksApplied = new Set<string>();
28	
29	  for (const item of items) {
30	    const isBlock = COMPONENT_TYPES.has(item.type) && componentCounts[item.type] === BLOCK_SIZE;
31	    if (isBlock && !blocksApplied.has(item.type)) {
32	      basePremium += BLOCK_PREMIUM;
33	      blocksApplied.add(item.type);
34	    } else if (!isBlock) {
35	      basePremium += BASE_PREMIUMS[item.type];
36	    }
37	  }
38	
39	  return [{ premium: basePremium + PROCESSING_FEE }];
40	}
